examples.source:
.serif { font-family: Georgia, "Times New Roman", serif; }
.sans  { font-family: Tahoma, Arial, sans-serif; }
.mono  { font-family: Consolas, "Courier New", monospace; }

.s1 { font-size: 0.85rem; font-weight: 300; }
.s2 { font-size: 1rem;    font-weight: 400; }
.s3 { font-size: 1.4rem;  font-weight: 700; }
.s4 { font-size: 2rem;    font-weight: 900; }
